transforms.code:

def findDecoder(decoderName, decoderList):
	for d in decoderList:
		if d['label'] == decoderName:
			return d['value']
	return -1
try:
	system.perspective.print("Searching for {0} in decoder list".format(value))
	system.perspective.print(self.getChild("root").custom.models)
	val = findDecoder(value, self.getChild("root").custom.models)

	return val
except Exception as e:
	system.perspective.print(str(e))
	return -1

